    protected void endLedgerVoucher()
    {
        next endLedgerVoucher();

        if(vendInvoiceJour.Recid && 
            vendInvoiceJour.UBSHasWarrantyRetention && 
            VendParameters::find().UBSWarrantyRetentionAutomated && 
            vendInvoiceJour.InvoiceAmount > 0 &&
            vendInvoiceJour.UBSWarrantyLedgerJournalId == "")
        {
            UBSProcessVendInvoiceRetention::processVendInvoiceRetention(vendInvoiceJour);
        }
    }
